332 
333     VPValue *Op;
334     if (match(&R, m_VPInstruction<VPInstruction::FirstOrderRecurrenceSplice>(
335                       m_VPValue(), m_VPValue(Op)))) {
336       Copy->setOperand(0, getValueForPart(Op, Part - 1));
337       Copy->setOperand(1, getValueForPart(Op, Part));
338       continue;
339     }
340     if (auto *VPR = dyn_cast<VPVectorPointerRecipe>(&R)) {
341       VPBuilder Builder(VPR);
342       const DataLayout &DL =
343           Plan.getScalarHeader()->getIRBasicBlock()->getDataLayout();
344       Type *IndexTy = DL.getIndexType(TypeInfo.inferScalarType(VPR));
345       Type *VFTy = TypeInfo.inferScalarType(&Plan.getVF());
346       VPValue *VF = Builder.createScalarZExtOrTrunc(
347           &Plan.getVF(), IndexTy, VFTy, DebugLoc::getUnknown());
348       // VFxUF does not wrap, so VF * Part also cannot wrap.
349       VPValue *VFxPart = Builder.createOverflowingOp(
350           Instruction::Mul, {VF, Plan.getConstantInt(IndexTy, Part)},
351           {true, true});
352       Copy->setOperand(0, VPR->getOperand(0));
353       Copy->addOperand(VFxPart);
354       continue;
355     }
356     if (auto *Red = dyn_cast<VPReductionRecipe>(&R)) {
357       auto *Phi = dyn_cast<VPReductionPHIRecipe>(R.getOperand(0));
358       if (Phi && Phi->isOrdered()) {
359         auto &Parts = VPV2Parts[Phi];
360         if (Part == 1) {
361           Parts.clear();
362           Parts.push_back(Red);
363         }
364         Parts.push_back(Copy->getVPSingleValue());
365         Phi->setOperand(1, Copy->getVPSingleValue());
366       }
367     }
368     if (auto *VEPR = dyn_cast<VPVectorEndPointerRecipe>(Copy)) {
369       // Materialize PartN offset for VectorEndPointer.
370       VEPR->setOperand(0, R.getOperand(0));
371       VEPR->setOperand(1, R.getOperand(1));
372       VEPR->materializeOffset(Part);
373       continue;
374     }
375 
376     remapOperands(Copy, Part);
377 
378     if (auto *ScalarIVSteps = dyn_cast<VPScalarIVStepsRecipe>(Copy))
379       addStartIndexForScalarSteps(ScalarIVSteps, Part);
380 
381     // Add operand indicating the part to generate code for, to recipes still
382     // requiring it.
383     if (isa<VPWidenCanonicalIVRecipe>(Copy))
384       Copy->addOperand(getConstantInt(Part));
