4391 bool LoopVectorizationPlanner::isCandidateForEpilogueVectorization(
4392     ElementCount VF) const {
4393   // Cross iteration phis such as fixed-order recurrences and FMaxNum/FMinNum
4394   // reductions need special handling and are currently unsupported.
4395   if (any_of(OrigLoop->getHeader()->phis(), [&](PHINode &Phi) {
4396         if (!Legal->isReductionVariable(&Phi))
4397           return Legal->isFixedOrderRecurrence(&Phi);
4398         RecurKind Kind =
4399             Legal->getRecurrenceDescriptor(&Phi).getRecurrenceKind();
4400         return RecurrenceDescriptor::isFPMinMaxNumRecurrenceKind(Kind);
4401       }))
4402     return false;
4403 
4404   // FindLast reductions and inductions without underlying PHI require special
4405   // handling and are currently not supported for epilogue vectorization.
4406   if (hasUnsupportedHeaderPhiRecipe(getPlanFor(VF)))
4407     return false;
4408 
4409   // Phis with uses outside of the loop require special handling and are
4410   // currently unsupported.
4411   for (const auto &Entry : Legal->getInductionVars()) {
4412     // Look for uses of the value of the induction at the last iteration.
4413     Value *PostInc =
4414         Entry.first->getIncomingValueForBlock(OrigLoop->getLoopLatch());
4415     for (User *U : PostInc->users())
4416       if (!OrigLoop->contains(cast<Instruction>(U)))
4417         return false;
4418     // Look for uses of penultimate value of the induction.
4419     for (User *U : Entry.first->users())
4420       if (!OrigLoop->contains(cast<Instruction>(U)))
4421         return false;
4422   }
4423 
4424   // Epilogue vectorization code has not been auditted to ensure it handles
4425   // non-latch exits properly.  It may be fine, but it needs auditted and
4426   // tested.
4427   // TODO: Add support for loops with an early exit.
4428   if (OrigLoop->getExitingBlock() != OrigLoop->getLoopLatch())
4429     return false;
4430 
4431   return true;
4432 }
